import { rm } from 'node:fs/promises';
import path from 'node:path';
import process from 'node:process';

const publicDir = path.join(process.cwd(), 'public');

// The Cloudflare Pages project deploys /public directly. Remove only files
// generated by the previous Vite release before creating the next bundle;
// source-owned public assets such as robots.txt and the favicon are preserved.
await rm(path.join(publicDir, 'assets'), { recursive: true, force: true });
await rm(path.join(publicDir, 'index.html'), { force: true });
